/* Generated by Trae Work */
/* OCR 文本解析器 — 从截图 OCR 文本中提取月度/每日用电数据 */
(function () {
  'use strict';

  window.OcrParser = {

    /**
     * 清理文本中的各种不可见 Unicode 字符
     */
    _cleanText: function (text) {
      return text
        .replace(/[\u2010\u2011\u2012\u2013\u2014\u2015\u2212\u00AD\u2018\u2019\u201C\u201D\uFE63\uFF0D]/g, '-')
        .replace(/[\u00A0\u2000-\u200F\u2028-\u202F\u205F\u3000\uFEFF]/g, ' ')
        .replace(/\[.*?\]/g, '');
    },

    /**
     * 解析月度电费电量数据
     * 核心策略：找到"X月"关键词 → 提取该行所有数字 → 取最后两个有效数值
     */
    parseMonthly: function (text) {
      var results = [];
      text = this._cleanText(text);
      var lines = text.split(/\n/);
      var currentYear = null;

      var yearMatch = text.match(/20\d{2}/);
      if (yearMatch) currentYear = parseInt(yearMatch[0]);
      if (!currentYear) currentYear = new Date().getFullYear();

      // 收集年累计值，用于排除
      var totals = [];
      var totalMatch = text.match(/年(?:电量)?(?:累计|总计)[^\d]*(\d+(?:\.\d+)?)/);
      if (totalMatch) totals.push(parseFloat(totalMatch[1]));
      var costTotalMatch = text.match(/年(?:电费)?(?:累计|总计)[^\d]*(\d+(?:\.\d+)?)/);
      if (costTotalMatch) totals.push(parseFloat(costTotalMatch[1]));

      lines.forEach(function (line) {
        line = line.trim();
        if (!line) return;
        if (/累计|总计|日均|平均|合计/.test(line)) return;

        // 找 "X月" 关键词
        var monthMatch = line.match(/(\d{1,2})月/);
        if (!monthMatch) return;
        var month = parseInt(monthMatch[1]);
        if (month < 1 || month > 12) return;

        // 提取该行所有数字
        var nums = line.match(/\d+(?:\.\d+)?/g);
        if (!nums || nums.length < 3) return;

        // 从后往前取两个有效数字作为电费和电量
        var kwh = null, cost = null;
        for (var i = nums.length - 1; i >= 1; i--) {
          var val = parseFloat(nums[i]);
          if (val > 0 && val < 5000) {
            if (cost === null) {
              cost = val;
            } else if (kwh === null) {
              kwh = val;
              break;
            }
          }
        }

        if (kwh !== null && cost !== null) {
          var isTotal = totals.indexOf(kwh) !== -1 || totals.indexOf(cost) !== -1;
          if (!isTotal) {
            results.push({ year: currentYear, month: month, kwh: kwh, cost: cost });
          }
        }
      });

      var seen = {};
      results = results.filter(function (r) {
        var key = r.year + '-' + r.month;
        if (seen[key]) return false;
        seen[key] = true;
        return true;
      });

      results.sort(function (a, b) {
        return (a.year * 12 + a.month) - (b.year * 12 + b.month);
      });

      return results;
    },

    /**
     * 解析每日用电量数据
     * 针对日历网格视图优化：识别日期-电量对，过滤统计值，标记可疑数据
     */
    parseDaily: function (text) {
      var results = [];
      text = this._cleanText(text);
      var lines = text.split(/\n/);
      var currentYear = new Date().getFullYear();
      var currentMonth = new Date().getMonth() + 1;

      var ymMatch = text.match(/(20\d{2})[\/\-.年](\d{1,2})/);
      if (ymMatch) {
        currentYear = parseInt(ymMatch[1]);
        currentMonth = parseInt(ymMatch[2]);
      }

      // 收集统计值用于排除（更全面的模式）
      var stats = [];
      var statPatterns = [
        /合计电量?[^\d]*(\d+(?:\.\d+)?)/i,
        /日均电量?[^\d]*(\d+(?:\.\d+)?)/i,
        /平均[^\d]*(\d+(?:\.\d+)?)/i,
        /峰电量?[^\d]*(\d+(?:\.\d+)?)/i,
        /谷电量?[^\d]*(\d+(?:\.\d+)?)/i,
        /合计[^\d]*(\d{3,}(?:\.\d+)?)/,
        /累计[^\d]*(\d{3,}(?:\.\d+)?)/
      ];
      statPatterns.forEach(function (p) {
        var m = text.match(p);
        if (m) stats.push(parseFloat(m[1]));
      });
      // 同时排除月份和年份本身
      stats.push(currentYear, currentMonth);

      lines.forEach(function (line) {
        line = line.trim();
        if (!line) return;
        // 过滤包含统计关键词的行
        if (/合计|日均|平均|峰电量|谷电量|累计|总计|切换户号|产品体验官/.test(line)) return;
        // 过滤界面文案行
        if (/日历视图|图表视图|用电明细|电量单位|每日用电|每月用电/.test(line)) return;
        // 过滤星期标题行（日一二三四五六）
        if (/^[\s日一二三四五六]+$/.test(line)) return;

        // 格式1: 完整日期 "2026-06-01 8.49"
        var m1 = line.match(/(20\d{2})[-\/.](\d{1,2})[-\/.](\d{1,2})\s+(\d+(?:\.\d+)?)/);
        if (m1) {
          var y = parseInt(m1[1]), mo = parseInt(m1[2]), d = parseInt(m1[3]), kwh = parseFloat(m1[4]);
          if (mo >= 1 && mo <= 12 && d >= 1 && d <= 31 && kwh > 0 && kwh < 200) {
            results.push({ date: y + '-' + String(mo).padStart(2, '0') + '-' + String(d).padStart(2, '0'), kwh: kwh, _warn: false });
            return;
          }
        }

        // 格式2: 月-日 "06-01 8.49"
        var m2 = line.match(/(\d{1,2})[-\/.](\d{1,2})\s+(\d+(?:\.\d+)?)/);
        if (m2) {
          var mo2 = parseInt(m2[1]), d2 = parseInt(m2[2]), kwh2 = parseFloat(m2[3]);
          if (mo2 >= 1 && mo2 <= 12 && d2 >= 1 && d2 <= 31 && kwh2 > 0 && kwh2 < 200) {
            if (stats.indexOf(kwh2) !== -1) return;
            results.push({ date: currentYear + '-' + String(mo2).padStart(2, '0') + '-' + String(d2).padStart(2, '0'), kwh: kwh2, _warn: false });
            return;
          }
        }

        // 格式3: 日历网格改进版
        // 先提取该行所有数字token
        var tokens = [];
        var numRe = /\d+(?:\.\d+)?/g;
        var nm;
        while ((nm = numRe.exec(line)) !== null) {
          var v = parseFloat(nm[0]);
          if (stats.indexOf(v) !== -1) continue;
          if (v > 500) continue; // 过滤超大数字（通常为误识别）
          tokens.push({ str: nm[0], val: v });
        }
        if (tokens.length < 2) return;

        // 配对策略：寻找 (日期1-31, 电量) 序列
        var i = 0;
        while (i < tokens.length) {
          var curr = tokens[i];
          var isDay = curr.val >= 1 && curr.val <= 31 && Number.isInteger(curr.val);

          if (isDay && i + 1 < tokens.length) {
            var next = tokens[i + 1];
            // 电量特征：小数，或合理范围内的整数
            var isKwh = (next.val > 0 && next.val < 100 && !Number.isInteger(next.val)) ||
                        (Number.isInteger(next.val) && next.val > 0 && next.val < 50);

            if (isKwh) {
              // 标记可疑数据：日电量通常不会 >40（除非极端天气）
              var suspicious = next.val > 40 || next.val < 0.5;
              results.push({
                date: currentYear + '-' + String(currentMonth).padStart(2, '0') + '-' + String(curr.val).padStart(2, '0'),
                kwh: next.val,
                _warn: suspicious
              });
              i += 2;
              continue;
            }
          }

          // 处理连在一起的情况：字符串以日期开头，后面跟着电量
          if (!isDay) {
            var str = curr.str;
            var found = false;
            for (var day = 1; day <= 31; day++) {
              var ds = String(day);
              if (str.startsWith(ds) && str.length > ds.length) {
                var rest = str.substring(ds.length);
                var rv = parseFloat(rest);
                if (!isNaN(rv) && rv > 0 && rv < 100) {
                  results.push({
                    date: currentYear + '-' + String(currentMonth).padStart(2, '0') + '-' + String(day).padStart(2, '0'),
                    kwh: rv,
                    _warn: rv > 40 || rv < 0.5
                  });
                  found = true;
                  break;
                }
              }
            }
            if (found) { i++; continue; }
          }

          i++;
        }
      });

      // 去重（保留第一次出现）
      var seen = {};
      results = results.filter(function (r) {
        if (seen[r.date]) return false;
        seen[r.date] = true;
        return true;
      });

      // 按日期排序
      results.sort(function (a, b) { return a.date < b.date ? -1 : 1; });

      // 连续性检查：标记日期跳变异常（如 13→15 缺少14）
      for (var j = 1; j < results.length; j++) {
        var prevDay = parseInt(results[j - 1].date.split('-')[2]);
        var currDay = parseInt(results[j].date.split('-')[2]);
        if (currDay !== prevDay + 1) {
          // 日期不连续，标记前后两条为可疑
          results[j - 1]._warn = true;
          results[j]._warn = true;
        }
      }

      return results;
    },

    /**
     * 将新数据合并到已有数据中
     */
    merge: function (existing, newData, type) {
      if (!existing || !Array.isArray(existing)) existing = [];
      var merged = existing.slice();
      var index = {};

      merged.forEach(function (item, i) {
        var key = type === 'monthly' ? (item.year + '-' + item.month) : item.date;
        index[key] = i;
      });

      newData.forEach(function (item) {
        var key = type === 'monthly' ? (item.year + '-' + item.month) : item.date;
        if (index[key] !== undefined) {
          merged[index[key]] = item;
        } else {
          merged.push(item);
          index[key] = merged.length - 1;
        }
      });

      if (type === 'monthly') {
        merged.sort(function (a, b) {
          return (a.year * 12 + a.month) - (b.year * 12 + b.month);
        });
      } else {
        merged.sort(function (a, b) {
          return a.date < b.date ? -1 : (a.date > b.date ? 1 : 0);
        });
      }

      return merged;
    }
  };
})();